import{_ as l,C as i,o as r,c as n,a2 as o,b as s,w as e,a as h,E as p,a3 as g}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"Java 进阶面试指南","description":"","frontmatter":{"title":"Java 进阶面试指南","module":"java-advanced","difficulty":"advanced","interviewFrequency":"high","tags":["面试指南","Java 进阶","高频面试题"],"relatedEntries":["/1-java-core/1.2-java-advanced/01-collections-source","/1-java-core/1.2-java-advanced/03-dynamic-proxy","/1-java-core/1.2-java-advanced/06-network-programming","/1-java-core/1.2-java-advanced/07-jmm"],"prerequisites":["/1-java-core/1.2-java-advanced/"],"estimatedTime":"60min"},"headers":[],"relativePath":"1-java-core/1.2-java-advanced/99-interview.md","filePath":"1-java-core/1.2-java-advanced/99-interview.md","lastUpdated":null}'),d={name:"1-java-core/1.2-java-advanced/99-interview.md"};function c(u,a,B,E,m,v){const t=i("Mermaid");return r(),n("div",null,[a[1]||(a[1]=o('<h1 id="java-进阶面试指南" tabindex="-1">Java 进阶面试指南 <a class="header-anchor" href="#java-进阶面试指南" aria-label="Permalink to &quot;Java 进阶面试指南&quot;">​</a></h1><h2 id="概念说明" tabindex="-1">概念说明 <a class="header-anchor" href="#概念说明" aria-label="Permalink to &quot;概念说明&quot;">​</a></h2><p>本文汇总 Java 进阶模块的高频面试题，按出现频率排序。建议在学习完各知识点后，用本指南进行系统复习和查漏补缺。每道题都标注了难度和频率，并提供追问链路帮助你应对面试官的深入追问。</p><h2 id="高频面试题汇总-按频率排序" tabindex="-1">高频面试题汇总（按频率排序） <a class="header-anchor" href="#高频面试题汇总-按频率排序" aria-label="Permalink to &quot;高频面试题汇总（按频率排序）&quot;">​</a></h2><h3 id="🔥🔥🔥-必考题-几乎每次面试都会问" tabindex="-1">🔥🔥🔥 必考题（几乎每次面试都会问） <a class="header-anchor" href="#🔥🔥🔥-必考题-几乎每次面试都会问" aria-label="Permalink to &quot;🔥🔥🔥 必考题（几乎每次面试都会问）&quot;">​</a></h3><h4 id="q1-hashmap-的底层实现原理-put-方法的执行流程" tabindex="-1">Q1: HashMap 的底层实现原理？put 方法的执行流程？ <a class="header-anchor" href="#q1-hashmap-的底层实现原理-put-方法的执行流程" aria-label="Permalink to &quot;Q1: HashMap 的底层实现原理？put 方法的执行流程？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥🔥🔥 | <strong>详细解析</strong>：<a href="./01-collections-source.html">集合源码分析</a></p><p><strong>答题要点</strong>：</p><ol><li>数据结构：数组 + 链表 + 红黑树（JDK 8+）</li><li>hash 扰动函数：<code>(h = key.hashCode()) ^ (h &gt;&gt;&gt; 16)</code></li><li>定位桶：<code>(n-1) &amp; hash</code></li><li>put 流程：空桶直接插入 → 首节点 key 相同则覆盖 → 红黑树插入 → 链表尾插</li><li>链表长度 ≥ 8 且数组 ≥ 64 转红黑树</li><li>size 超过阈值则扩容（容量翻倍）</li></ol><p><strong>追问链路</strong>：</p><ul><li>→ 为什么用扰动函数？ → 为什么阈值是 8？ → JDK 7 和 8 的区别？ → 头插法为什么会死循环？ → HashMap 线程不安全的表现？</li></ul><hr><h4 id="q2-concurrenthashmap-的实现原理-jdk-7-和-8-的区别" tabindex="-1">Q2: ConcurrentHashMap 的实现原理？JDK 7 和 8 的区别？ <a class="header-anchor" href="#q2-concurrenthashmap-的实现原理-jdk-7-和-8-的区别" aria-label="Permalink to &quot;Q2: ConcurrentHashMap 的实现原理？JDK 7 和 8 的区别？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥🔥🔥 | <strong>详细解析</strong>：<a href="./01-collections-source.html">集合源码分析</a></p><p><strong>答题要点</strong>：</p><ol><li>JDK 7：Segment 分段锁（ReentrantLock），并发度 16</li><li>JDK 8：CAS + synchronized 锁桶头节点，并发度 = 桶数量</li><li>size() 使用 LongAdder 思想的分段计数</li><li>key 和 value 都不允许 null</li></ol><p><strong>追问链路</strong>：</p><ul><li>→ 为什么 JDK 8 用 synchronized 而不是 ReentrantLock？ → size() 如何保证准确？ → 和 Hashtable 的区别？</li></ul><hr><h4 id="q3-jdk-动态代理和-cglib-代理的区别-spring-如何选择" tabindex="-1">Q3: JDK 动态代理和 CGLIB 代理的区别？Spring 如何选择？ <a class="header-anchor" href="#q3-jdk-动态代理和-cglib-代理的区别-spring-如何选择" aria-label="Permalink to &quot;Q3: JDK 动态代理和 CGLIB 代理的区别？Spring 如何选择？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥🔥🔥 | <strong>详细解析</strong>：<a href="./03-dynamic-proxy.html">动态代理</a></p><p><strong>答题要点</strong>：</p><ol><li>JDK 代理：基于接口，Proxy + InvocationHandler</li><li>CGLIB 代理：基于继承，生成子类，不能代理 final</li><li>Spring 选择策略：有接口用 JDK，无接口用 CGLIB</li><li>Spring Boot 2.x 默认 CGLIB</li></ol><p><strong>追问链路</strong>：</p><ul><li>→ Spring Boot 为什么默认改用 CGLIB？ → @Transactional 失效场景？ → 自调用为什么 AOP 失效？</li></ul><hr><h4 id="q4-什么是-jmm-happens-before-规则有哪些" tabindex="-1">Q4: 什么是 JMM？happens-before 规则有哪些？ <a class="header-anchor" href="#q4-什么是-jmm-happens-before-规则有哪些" aria-label="Permalink to &quot;Q4: 什么是 JMM？happens-before 规则有哪些？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥🔥🔥 | <strong>详细解析</strong>：<a href="./07-jmm.html">JMM 与 happens-before</a></p><p><strong>答题要点</strong>：</p><ol><li>JMM 定义多线程变量访问规则（主内存 + 工作内存）</li><li>8 条 happens-before 规则</li><li>重点：volatile 规则、锁规则、传递性</li><li>JMM ≠ JVM 内存区域</li></ol><p><strong>追问链路</strong>：</p><ul><li>→ JMM 和 JVM 内存区域的区别？ → 什么是指令重排序？ → volatile 如何防止重排序？ → DCL 为什么需要 volatile？</li></ul><hr><h4 id="q5-bio、nio、aio-的区别-netty-的线程模型" tabindex="-1">Q5: BIO、NIO、AIO 的区别？Netty 的线程模型？ <a class="header-anchor" href="#q5-bio、nio、aio-的区别-netty-的线程模型" aria-label="Permalink to &quot;Q5: BIO、NIO、AIO 的区别？Netty 的线程模型？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥🔥🔥 | <strong>详细解析</strong>：<a href="./06-network-programming.html">网络编程</a></p><p><strong>答题要点</strong>：</p><ol><li>BIO：同步阻塞，一连接一线程</li><li>NIO：同步非阻塞，Selector 多路复用</li><li>AIO：异步非阻塞，回调通知</li><li>Netty：主从 Reactor 模型，BossGroup + WorkerGroup</li></ol><p><strong>追问链路</strong>：</p><ul><li>→ NIO 的 Selector 底层实现？ → epoll 和 select 的区别？ → Netty 如何解决 epoll 空轮询 Bug？ → 什么是零拷贝？</li></ul><hr><h3 id="🔥🔥-高频题-经常出现" tabindex="-1">🔥🔥 高频题（经常出现） <a class="header-anchor" href="#🔥🔥-高频题-经常出现" aria-label="Permalink to &quot;🔥🔥 高频题（经常出现）&quot;">​</a></h3><h4 id="q6-什么是双亲委派模型-如何打破" tabindex="-1">Q6: 什么是双亲委派模型？如何打破？ <a class="header-anchor" href="#q6-什么是双亲委派模型-如何打破" aria-label="Permalink to &quot;Q6: 什么是双亲委派模型？如何打破？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥🔥 | <strong>详细解析</strong>：<a href="./02-classloader.html">类加载机制</a></p><p><strong>答题要点</strong>：</p><ol><li>委派流程：先委派父加载器，父无法加载再自己加载</li><li>三个优点：安全性、唯一性、层次性</li><li>打破场景：SPI（线程上下文类加载器）、Tomcat、OSGi</li></ol><p><strong>追问链路</strong>：</p><ul><li>→ 如何自定义 ClassLoader？ → findClass 和 loadClass 的区别？ → JDBC 驱动如何通过 SPI 加载？</li></ul><hr><h4 id="q7-java-spi-机制是什么-有什么缺点" tabindex="-1">Q7: Java SPI 机制是什么？有什么缺点？ <a class="header-anchor" href="#q7-java-spi-机制是什么-有什么缺点" aria-label="Permalink to &quot;Q7: Java SPI 机制是什么？有什么缺点？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：🔥🔥 | <strong>详细解析</strong>：<a href="./04-spi.html">SPI 机制</a></p><p><strong>答题要点</strong>：</p><ol><li>ServiceLoader + META-INF/services 配置</li><li>应用：JDBC、SLF4J、Dubbo、Spring Boot</li><li>缺点：全量加载、无排序、无依赖注入</li><li>Dubbo SPI 的改进</li></ol><p><strong>追问链路</strong>：</p><ul><li>→ Dubbo SPI 和 Java SPI 的区别？ → Spring Boot 的 spring.factories 是什么？</li></ul><hr><h4 id="q8-java-有哪些序列化方式-如何选择" tabindex="-1">Q8: Java 有哪些序列化方式？如何选择？ <a class="header-anchor" href="#q8-java-有哪些序列化方式-如何选择" aria-label="Permalink to &quot;Q8: Java 有哪些序列化方式？如何选择？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：🔥🔥 | <strong>详细解析</strong>：<a href="./05-serialization.html">序列化机制</a></p><p><strong>答题要点</strong>：</p><ol><li>Java 原生：Serializable，性能差，安全风险</li><li>JSON：Jackson（推荐）、Gson、Fastjson</li><li>二进制：Protobuf（高性能跨语言）、Kryo（Java 内部）</li><li>serialVersionUID 的作用</li></ol><p><strong>追问链路</strong>：</p><ul><li>→ 为什么不推荐 Java 原生序列化？ → Fastjson 的安全问题？ → Protobuf 为什么比 JSON 快？</li></ul><hr><h4 id="q9-linkedhashmap-如何实现-lru-缓存" tabindex="-1">Q9: LinkedHashMap 如何实现 LRU 缓存？ <a class="header-anchor" href="#q9-linkedhashmap-如何实现-lru-缓存" aria-label="Permalink to &quot;Q9: LinkedHashMap 如何实现 LRU 缓存？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：🔥🔥 | <strong>详细解析</strong>：<a href="./01-collections-source.html">集合源码分析</a></p><p><strong>答题要点</strong>：</p><ol><li>accessOrder = true，按访问顺序排列</li><li>重写 removeEldestEntry 方法</li><li>双向链表维护顺序</li></ol><p><strong>追问链路</strong>：</p><ul><li>→ 如何实现线程安全的 LRU？ → Redis 的 LRU 淘汰策略？</li></ul><hr><h3 id="🔥-中频题-偶尔出现" tabindex="-1">🔥 中频题（偶尔出现） <a class="header-anchor" href="#🔥-中频题-偶尔出现" aria-label="Permalink to &quot;🔥 中频题（偶尔出现）&quot;">​</a></h3><h4 id="q10-什么是零拷贝-有哪些实现方式" tabindex="-1">Q10: 什么是零拷贝？有哪些实现方式？ <a class="header-anchor" href="#q10-什么是零拷贝-有哪些实现方式" aria-label="Permalink to &quot;Q10: 什么是零拷贝？有哪些实现方式？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥 | <strong>详细解析</strong>：<a href="./06-network-programming.html">网络编程</a></p><p><strong>答题要点</strong>：</p><ol><li>传统 IO 4 次拷贝</li><li>sendfile：内核空间直接传输</li><li>mmap：内存映射</li><li>Netty 的零拷贝：CompositeByteBuf、FileRegion</li></ol><hr><h4 id="q11-什么是内存屏障-volatile-如何使用内存屏障" tabindex="-1">Q11: 什么是内存屏障？volatile 如何使用内存屏障？ <a class="header-anchor" href="#q11-什么是内存屏障-volatile-如何使用内存屏障" aria-label="Permalink to &quot;Q11: 什么是内存屏障？volatile 如何使用内存屏障？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥 | <strong>详细解析</strong>：<a href="./07-jmm.html">JMM 与 happens-before</a></p><p><strong>答题要点</strong>：</p><ol><li>四种屏障：LoadLoad、StoreStore、LoadStore、StoreLoad</li><li>volatile 写前 StoreStore，写后 StoreLoad</li><li>volatile 读后 LoadLoad + LoadStore</li></ol><hr><h2 id="面试知识图谱" tabindex="-1">面试知识图谱 <a class="header-anchor" href="#面试知识图谱" aria-label="Permalink to &quot;面试知识图谱&quot;">​</a></h2>',81)),(r(),s(g,null,{default:e(()=>[p(t,{id:"mermaid-461",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20A%5B%22Java%20%E8%BF%9B%E9%98%B6%22%5D%20--%3E%20B%5B%22%E9%9B%86%E5%90%88%E6%BA%90%E7%A0%81%22%5D%0A%20%20%20%20A%20--%3E%20C%5B%22%E7%B1%BB%E5%8A%A0%E8%BD%BD%22%5D%0A%20%20%20%20A%20--%3E%20D%5B%22%E5%8A%A8%E6%80%81%E4%BB%A3%E7%90%86%22%5D%0A%20%20%20%20A%20--%3E%20E%5B%22SPI%22%5D%0A%20%20%20%20A%20--%3E%20F%5B%22%E5%BA%8F%E5%88%97%E5%8C%96%22%5D%0A%20%20%20%20A%20--%3E%20G%5B%22%E7%BD%91%E7%BB%9C%E7%BC%96%E7%A8%8B%22%5D%0A%20%20%20%20A%20--%3E%20H%5B%22JMM%22%5D%0A%0A%20%20%20%20B%20--%3E%20B1%5B%22HashMap%20put%20%E6%B5%81%E7%A8%8B%22%5D%0A%20%20%20%20B%20--%3E%20B2%5B%22ConcurrentHashMap%22%5D%0A%20%20%20%20B%20--%3E%20B3%5B%22LinkedHashMap%20LRU%22%5D%0A%20%20%20%20%0A%20%20%20%20C%20--%3E%20C1%5B%22%E5%8F%8C%E4%BA%B2%E5%A7%94%E6%B4%BE%22%5D%0A%20%20%20%20C%20--%3E%20C2%5B%22%E6%89%93%E7%A0%B4%E5%8F%8C%E4%BA%B2%E5%A7%94%E6%B4%BE%22%5D%0A%20%20%20%20C%20--%3E%20E%0A%20%20%20%20%0A%20%20%20%20D%20--%3E%20D1%5B%22JDK%20%E4%BB%A3%E7%90%86%20vs%20CGLIB%22%5D%0A%20%20%20%20D%20--%3E%20D2%5B%22Spring%20AOP%20%E9%80%89%E6%8B%A9%22%5D%0A%20%20%20%20%0A%20%20%20%20G%20--%3E%20G1%5B%22BIO%2FNIO%2FAIO%22%5D%0A%20%20%20%20G%20--%3E%20G2%5B%22Netty%20%E7%BA%BF%E7%A8%8B%E6%A8%A1%E5%9E%8B%22%5D%0A%20%20%20%20G%20--%3E%20G3%5B%22%E9%9B%B6%E6%8B%B7%E8%B4%9D%22%5D%0A%20%20%20%20%0A%20%20%20%20H%20--%3E%20H1%5B%22happens-before%22%5D%0A%20%20%20%20H%20--%3E%20H2%5B%22%E6%8C%87%E4%BB%A4%E9%87%8D%E6%8E%92%E5%BA%8F%22%5D%0A%20%20%20%20H%20--%3E%20H3%5B%22%E5%86%85%E5%AD%98%E5%B1%8F%E9%9A%9C%22%5D%0A"})]),fallback:e(()=>[...a[0]||(a[0]=[h(" Loading... ",-1)])]),_:1})),a[2]||(a[2]=o('<h2 id="面试技巧" tabindex="-1">面试技巧 <a class="header-anchor" href="#面试技巧" aria-label="Permalink to &quot;面试技巧&quot;">​</a></h2><ol><li><strong>HashMap 系列</strong>：从数据结构讲起，重点是 put 流程和扩容，主动提到 JDK 7/8 区别展示深度</li><li><strong>代理系列</strong>：先讲区别，再讲 Spring 选择策略，主动关联 @Transactional 失效场景</li><li><strong>网络编程</strong>：从 BIO 的问题引出 NIO，再引出 Netty，展示知识的连贯性</li><li><strong>JMM 系列</strong>：先区分 JMM 和 JVM 内存区域，再讲 happens-before，用 volatile 举例</li></ol><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://javaguide.cn/" target="_blank" rel="noreferrer">Java 面试指南</a></li><li><a href="https://xiaolincoding.com/" target="_blank" rel="noreferrer">小林 coding</a></li></ul>',4))])}const q=l(d,[["render",c]]);export{b as __pageData,q as default};
